/* ===== src/content/modules/utils.js ===== */
(() => {
  const ns = window.HtmlSlideMenderExtension = window.HtmlSlideMenderExtension || {};
  const { DEFAULT_LANG } = ns.constants;

  function normalizeText(value) {
    return String(value).replace(/\s+/g, " ").trim();
  }

  function isRendered(style) {
    return style.display !== "none" &&
      style.visibility !== "hidden" &&
      Number(style.opacity || "1") > 0.02;
  }

  function isVisibleRect(rect, minWidth, minHeight) {
    return rect.width >= minWidth &&
      rect.height >= minHeight &&
      rect.width * rect.height >= minWidth * minHeight;
  }

  function intersectsViewport(rect) {
    const left = Math.max(rect.left, 0);
    const top = Math.max(rect.top, 0);
    const right = Math.min(rect.right, window.innerWidth);
    const bottom = Math.min(rect.bottom, window.innerHeight);
    return right - left > 2 && bottom - top > 2;
  }

  function hasTextOverflow(element) {
    return element.scrollWidth > element.clientWidth + 2 ||
      element.scrollHeight > element.clientHeight + 2;
  }

  function round(value, precision = 1) {
    const factor = 10 ** precision;
    return Math.round(value * factor) / factor;
  }

  function clamp(value, min, max) {
    return Math.min(max, Math.max(min, value));
  }

  function sameState(a, b) {
    return JSON.stringify(a) === JSON.stringify(b);
  }

  function restoreAttr(element, name, value) {
    if (value === null || value === undefined || value === "") {
      element.removeAttribute(name);
    } else {
      element.setAttribute(name, value);
    }
  }

  function escapeHtml(value) {
    return String(value)
      .replaceAll("&", "&amp;")
      .replaceAll("<", "&lt;")
      .replaceAll(">", "&gt;");
  }

  function escapeAttr(value) {
    return escapeHtml(value).replaceAll("\"", "&quot;");
  }

  function readFileAsDataUrl(file) {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = () => resolve(String(reader.result));
      reader.onerror = () => reject(reader.error || new Error("Failed to read file."));
      reader.readAsDataURL(file);
    });
  }

  function toHexColor(value) {
    const match = String(value).match(/rgba?\((\d+),\s*(\d+),\s*(\d+)(?:,\s*([0-9.]+))?\)/i);
    if (!match || match[4] === "0") {
      return "";
    }
    return `#${[match[1], match[2], match[3]]
      .map((part) => Number(part).toString(16).padStart(2, "0"))
      .join("")}`;
  }

  function filenameFromTitle(title) {
    const safe = normalizeText(title || "edited-html-slide")
      .replace(/[\\/:*?"<>|]+/g, "-")
      .slice(0, 90);
    return `${safe || "edited-html-slide"}-edited.html`;
  }

  function normalizeLanguage(language) {
    return language === "en" ? "en" : DEFAULT_LANG;
  }

  ns.utils = {
    normalizeText,
    isRendered,
    isVisibleRect,
    intersectsViewport,
    hasTextOverflow,
    round,
    clamp,
    sameState,
    restoreAttr,
    escapeHtml,
    escapeAttr,
    readFileAsDataUrl,
    toHexColor,
    filenameFromTitle,
    normalizeLanguage
  };
})();



/* ===== src/content/modules/selection.js ===== */
(() => {
  const ns = window.HtmlSlideMenderExtension = window.HtmlSlideMenderExtension || {};

  function placeCaretAtEnd(element) {
    const range = document.createRange();
    range.selectNodeContents(element);
    range.collapse(false);
    const selection = window.getSelection();
    selection.removeAllRanges();
    selection.addRange(range);
  }

  function placeCaretFromPoint(element, x, y) {
    const range = document.caretRangeFromPoint?.(x, y) || caretPositionRangeFromPoint(x, y);
    if (!range || !rangeBelongsTo(range, element)) {
      placeCaretAtEnd(element);
      return;
    }

    range.collapse(true);
    const selection = window.getSelection();
    selection.removeAllRanges();
    selection.addRange(range);
  }

  function caretPositionRangeFromPoint(x, y) {
    const position = document.caretPositionFromPoint?.(x, y);
    if (!position) {
      return null;
    }
    const range = document.createRange();
    range.setStart(position.offsetNode, position.offset);
    return range;
  }

  function selectElementContents(element) {
    const range = document.createRange();
    range.selectNodeContents(element);
    const selection = window.getSelection();
    selection.removeAllRanges();
    selection.addRange(range);
  }

  function rangeBelongsTo(range, element) {
    return nodeBelongsTo(range.startContainer, element) &&
      nodeBelongsTo(range.endContainer, element) &&
      nodeBelongsTo(range.commonAncestorContainer, element);
  }

  function nodeBelongsTo(node, element) {
    return node === element ||
      element.contains(node.nodeType === Node.ELEMENT_NODE ? node : node.parentElement);
  }

  ns.selection = {
    placeCaretAtEnd,
    placeCaretFromPoint,
    selectElementContents,
    rangeBelongsTo
  };
})();



